mapper.select:
select coalesce(sum(planned_amount), 0)
from cost_plan
where project_id = #{projectId}
  and task_id = #{taskId}
  and cost_type = 'LABOR'
  and is_deleted = 0

select count(1)
from baseline_record
where project_id = #{projectId}
  and baseline_type = #{baselineType}

select id, project_id, baseline_name, snapshot_json, published_at
from baseline_record
where project_id = #{projectId}
  and baseline_type = #{baselineType}
order by published_at desc, id desc

